def perceive(data):
    if isinstance(data, dict):
        feed = data
    else:
        feed = {}
        for line in str(data).splitlines():
            if ":" in line:
                k, _, v = line.partition(":")
                feed[k.strip().lower()] = v.strip()
    out = {}
    for key in ("cash", "deposits", "borrowings"):
        if key in feed:
            try:
                out[key] = float(feed[key])
            except (ValueError, TypeError):
                pass
    return out
